export type JsonPrimitive = string | number | boolean | null;
export type JsonValue = JsonPrimitive | JsonObject | JsonValue[];
export interface JsonObject {
    [key: string]: JsonValue | undefined;
}
export type TimeoutProfile = "short" | "standard" | "long_poll";
export interface TimeoutPolicy {
    shortMs?: number;
    standardMs?: number;
    longPollMs?: number;
}
export type RetryErrorKind = "timed_out" | "network_error" | "conflict" | "retry_after" | "bad_request" | "forbidden" | "invalid_token" | "zalo_error";
export interface RetryPolicy {
    maxAttempts?: number;
    baseDelayMs?: number;
    maxDelayMs?: number;
    jitterRatio?: number;
    retryOn?: RetryErrorKind[];
}
export interface RequestAttemptContext {
    url: string;
    method: "GET" | "POST";
    data?: Record<string, unknown>;
    attempt: number;
}
export interface RequestResponseContext extends RequestAttemptContext {
    durationMs: number;
    responseStatus?: number;
    responseBody?: string;
    error?: unknown;
}
export interface RequestHooks {
    beforeRequest?: (context: RequestAttemptContext) => Promise<void> | void;
    afterResponse?: (context: RequestResponseContext) => Promise<void> | void;
}
export interface RequestOptions {
    readTimeout?: number;
    writeTimeout?: number;
    connectTimeout?: number;
    poolTimeout?: number;
    signal?: AbortSignal;
    timeoutProfile?: TimeoutProfile;
    timeoutPolicy?: TimeoutPolicy;
    retryPolicy?: RetryPolicy;
    hooks?: RequestHooks;
}
